<section class="hero-section" id="hero" aria-labelledby="hero-heading">
    <div class="hero-inner">

      <!-- ════════════════════════════
           LEFT — Copy + CTAs + Trust
      ════════════════════════════ -->
      <div class="hero-left">

        <!-- Eyebrow badge -->
        <div class="hero-eyebrow-badge" aria-label="Live classes available now">
          <span class="eyebrow-pip" aria-hidden="true"></span>
          500+ Students Enrolled Worldwide
        </div>

        <!-- Spec 1: Headline — bold, 40–48px, #0B3D91 -->
        <!-- Answers: "What is this?" instantly -->
        <h1 class="hero-h1" id="hero-heading">
          Learn Quran Online with<br/>
          <span class="h1-accent">Certified Teachers</span><br/>
          from Home
        </h1>

        <!-- Spec 2: Subheadline — emotional + benefit, 16–18px, #555555, max 560px -->
