          <div class="testi-avatar-box" aria-hidden="true">A</div>
          <div class="testi-body">
            <p class="testi-quote">
              "I learned Quran online easily with expert guidance —
               highly recommend NoorPath!"
            </p>
            <div class="testi-meta">
              <span style="font-size:13px;" aria-hidden="true">🇬🇧</span>
              <span class="testi-name">Amina, Student</span>
              <span style="color:#d1d5db; font-size:11px;">·</span>
              <span class="testi-stars" aria-label="5 stars">★★★★★</span>
            </div>
          </div>
        </div>

      </div><!-- /hero-left -->


      <!-- ════════════════════════════
           RIGHT — Image + floating cards
      ════════════════════════════ -->
      <div class="hero-right" aria-label="Live Quran class on NoorPath Academy">

        <!-- Spec 6: Image frame — shadow, rounded corners 12px, 90–95% size -->
        <div class="hero-img-frame">
          <img src="data:image/jpeg;base64,"
               alt="NoorPath Academy online Quran class — certified teacher guiding a student in a live 1-on-1 session via video call, with Quran open on desk"
               loading="eager"
               decoding="async"
               fetchpriority="high" />
        </div>

        <!-- Floating rating card — bottom-left -->
        <div class="img-card-rating" aria-label="Rated 4.9 out of 5">
          <div class="rating-star-box" aria-hidden="true">⭐</div>
