        </div>

        <!-- Floating live indicator — top-right -->
        <div class="img-card-students" aria-label="500+ active students">
          <div class="student-avatars" aria-hidden="true">
            <div class="student-av av-gold">A</div>
            <div class="student-av av-blue">O</div>
            <div class="student-av av-rose">F</div>
            <div class="student-av av-violet">Y</div>
          </div>
          <div class="student-info">
            <div class="student-count">500+</div>
            <div class="student-label">Active Students</div>
          </div>
        </div>

      </div><!-- /hero-right -->

